import { useState } from "react";

function AddProject() {
    const [form, setForm] = useState({
        title: "",
        description: "",
        shortDescription: "",
        category: "",
        year: "",
        image: null,
        tech: "",
        liveLink: "",
        longDescription: "",
        result: ""
    });

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };
    const handleSubmit = (e) => {
        e.preventDefault();

        const formData = new FormData();

        formData.append("title", form.title);
        formData.append("description", form.description);
        formData.append("shortDescription", form.shortDescription);
        formData.append("category", form.category);
        formData.append("year", form.year);
        formData.append("image", form.image); // ✅ file
        formData.append("tech", JSON.stringify(form.tech.split(",")));
        formData.append("liveLink", form.liveLink);
        formData.append("longDescription", form.longDescription);
        formData.append("result", form.result);

        console.log("FormData ready", formData);
    };

    const handleFileChange = (e) => {
        setForm({
            ...form,
            image: e.target.files[0]
        });
    };

    return (
        <div>
            <h2>Add Project</h2>

            <form onSubmit={handleSubmit}>

                <input name="title" placeholder="Title" onChange={handleChange} /><br /><br />
                <input name="category" placeholder="Category" onChange={handleChange} /><br /><br />
                <input name="year" placeholder="Year" onChange={handleChange} /><br /><br />

                <input type="file" name="image" onChange={handleFileChange} /><br /><br />

                <input name="shortDescription" placeholder="Short Description" onChange={handleChange} /><br /><br />

                <textarea name="description" placeholder="Description" onChange={handleChange}></textarea><br /><br />

                <textarea name="longDescription" placeholder="Long Description"></textarea><br /><br />

                <input name="tech" placeholder="Tech (comma separated)" onChange={handleChange} /><br /><br />

                <input name="liveLink" placeholder="Live Link" onChange={handleChange} /><br /><br />

                <textarea name="result" placeholder="Result"></textarea><br /><br />

                https://example.com

            </form>
        </div>
    );
}

export default AddProject;
